import{c as h,Z as r,Q as u,j as p,g as t,n as o,o as n,m as a,av as s}from"./chunks/framework.BPKcPtvA.js";const v=JSON.parse('{"title":"The 10-minute happy path","description":"The flagship MuHaven flow end to end — sign in, fund, buy an encrypted position, reveal it, ask the agent, and verify on-chain.","frontmatter":{"title":"The 10-minute happy path","description":"The flagship MuHaven flow end to end — sign in, fund, buy an encrypted position, reveal it, ask the agent, and verify on-chain."},"headers":[],"relativePath":"guide/happy-path.md","filePath":"guide/happy-path.md","lastUpdated":1780203186000}'),c={name:"guide/happy-path.md"};function d(g,e,m,y,b,k){const l=r("TaskMeta"),i=r("ExpectedResult");return u(),p("div",null,[e[2]||(e[2]=t("h1",{id:"⭐-the-10-minute-happy-path",tabindex:"-1"},[o("⭐ The 10-minute happy path "),t("a",{class:"header-anchor",href:"#⭐-the-10-minute-happy-path","aria-label":'Permalink to "⭐ The 10-minute happy path"'},"​")],-1)),e[3]||(e[3]=t("p",null,[o("This is the single flow to run if you're evaluating MuHaven. It takes you from nothing to a "),t("strong",null,"confidential, on-chain real-world-asset position you can prove exists but no one else can read"),o(" — then shows the agent reading it and the transaction on a public explorer.")],-1)),n(l,{time:"~10 min",role:"Investor",needs:"A browser + a passkey device"}),e[4]||(e[4]=a('<blockquote><p><strong>What you&#39;ll do:</strong> sign in with a passkey → get testnet USDC → convert it to mhUSDC → buy an encrypted position → reveal your own balance → ask HavenBot about it → verify the trade on Arbiscan.</p></blockquote><div class="tip custom-block"><p class="custom-block-title">Each step links to its full task page</p><p>If a step needs more detail (edge cases, troubleshooting), follow the link in its heading. Otherwise just keep going down this page.</p></div><h2 id="_1-·-sign-in-with-a-passkey-·-1-min" tabindex="-1">1 · Sign in with a passkey · ~1 min <a class="header-anchor" href="#_1-·-sign-in-with-a-passkey-·-1-min" aria-label="Permalink to &quot;1 · Sign in with a passkey · ~1 min&quot;">​</a></h2><p><a href="/guide/investor/sign-in">Full task → I1</a></p><ol><li>Open <a href="https://muhaven.app" target="_blank" rel="noreferrer"><strong>muhaven.app</strong></a> and click <strong>Launch App</strong> — you&#39;ll be taken to the login page.</li><li>Use the link at the bottom to switch to <strong>Create account</strong>, pick the <strong>Investor</strong> role, name your passkey, and click <strong>Create Account</strong>.</li><li>Approve with your device (Touch ID / Windows Hello / security key).</li></ol><div class="tip custom-block"><p class="custom-block-title">Easiest passkey option on Chrome/Android</p><p>When prompted, choose <strong>Google Password Manager</strong> — it saves your passkey to your Google account and syncs it across devices, so you don&#39;t need a hardware key or a specific OS. It&#39;s the smoothest option for testing.</p></div><p>You land on your <strong>Portfolio</strong>. To fund, open <strong>Cash</strong> from the sidebar.</p><h2 id="_2-·-get-testnet-usdc-·-1–2-min" tabindex="-1">2 · Get testnet USDC · ~1–2 min <a class="header-anchor" href="#_2-·-get-testnet-usdc-·-1–2-min" aria-label="Permalink to &quot;2 · Get testnet USDC · ~1–2 min&quot;">​</a></h2><p><a href="/guide/investor/get-funds">Full task → I2</a></p><ol><li>Open the <strong>Cash</strong> page from the sidebar and copy your wallet address with <strong>Copy</strong>.</li><li>Click <strong>Get test USDC</strong> to open <a href="https://faucet.circle.com/" target="_blank" rel="noreferrer">faucet.circle.com</a>.</li><li>In the faucet, pick <strong>Arbitrum Sepolia</strong>, paste your address, and click <strong>Send 20 USDC</strong>.</li><li>Back in MuHaven, your USDC tile lights up with a gold bloom when the funds land (usually under a minute).</li></ol><h2 id="_3-·-convert-usdc-→-mhusdc-·-1-min" tabindex="-1">3 · Convert USDC → mhUSDC · ~1 min <a class="header-anchor" href="#_3-·-convert-usdc-→-mhusdc-·-1-min" aria-label="Permalink to &quot;3 · Convert USDC → mhUSDC · ~1 min&quot;">​</a></h2><p><a href="/guide/investor/deposit">Full task → I3</a></p><ol><li>On <strong>Cash</strong>, keep the toggle on <strong>Deposit</strong>.</li><li>Type an amount (e.g. <strong>100</strong>) or tap a quick-amount chip (<strong>$100 / $1,000 / $5,000</strong>).</li><li>Click <strong>Convert to mhUSDC</strong> and approve.</li></ol><p>Two quick steps run — <strong>Approve USDC</strong>, then <strong>Mint mhUSDC</strong> — and your encrypted mhUSDC balance appears.</p><h2 id="_4-·-buy-an-encrypted-position-·-2-min" tabindex="-1">4 · Buy an encrypted position · ~2 min <a class="header-anchor" href="#_4-·-buy-an-encrypted-position-·-2-min" aria-label="Permalink to &quot;4 · Buy an encrypted position · ~2 min&quot;">​</a></h2><p><a href="/guide/investor/buy">Full task → I5</a></p><ol><li>Go to <strong>Trade</strong> (or open a token from <strong>Marketplace</strong> and click its buy CTA, which routes you to <code>/trade</code>).</li><li>Choose a token (e.g. <strong>TBILL1</strong>) and enter a quantity.</li><li>If your mhUSDC balance shows as locked, click <strong>Reveal mhUSDC to continue</strong> — one tap, no transaction. This is the encrypted-balance gate doing its job.</li><li>Click <strong>Buy TBILL1</strong> (the CTA reads <code>Buy &lt;SYMBOL&gt;</code>) and approve.</li></ol><div class="tip custom-block"><p class="custom-block-title">This is the core privacy claim</p><p>The exact amount you spend is <strong>encrypted before it ever touches the chain</strong>. The purchase mints your shares atomically without your cleartext amount appearing on-chain.</p></div><h2 id="_5-·-reveal-your-balance-—-the-aha-·-instant" tabindex="-1">5 · Reveal your balance — the &quot;aha&quot; · instant <a class="header-anchor" href="#_5-·-reveal-your-balance-—-the-aha-·-instant" aria-label="Permalink to &quot;5 · Reveal your balance — the &quot;aha&quot; · instant&quot;">​</a></h2><p><a href="/guide/investor/reveal-balance">Full task → I6</a></p><ol><li>Open <strong>Portfolio</strong>.</li><li>Your new holding shows a <strong>lock</strong> icon instead of a number.</li><li>Click <strong>Decrypt</strong> on the holding card (or <strong>Reveal All</strong> at the top of the Holdings section). The number decrypts <strong>locally in your browser</strong> with a permit — no transaction, and no one else can do this for your balance.</li></ol>',21)),n(i,null,{default:s(()=>[...e[0]||(e[0]=[o(" Your position is visible to ",-1),t("em",null,"you",-1),o(" as a real number, but on-chain it's still an encrypted handle. That's the whole point: ",-1),t("strong",null,"provably yours, publicly unreadable.",-1)])]),_:1}),e[5]||(e[5]=a('<h2 id="_6-·-ask-havenbot-about-it-·-1-min" tabindex="-1">6 · Ask HavenBot about it · ~1 min <a class="header-anchor" href="#_6-·-ask-havenbot-about-it-·-1-min" aria-label="Permalink to &quot;6 · Ask HavenBot about it · ~1 min&quot;">​</a></h2><p><a href="/guide/agent/chat">Full task → H1</a></p><ol><li>Open <strong>Agent</strong> (the HavenBot chat).</li><li>Type: <em>&quot;Summarise my portfolio.&quot;</em></li><li>HavenBot reads your aggregates and replies — <strong>without ever holding your key</strong> and without seeing your cleartext amounts (it works on encrypted aggregates and the numbers you&#39;ve revealed).</li></ol><blockquote><p><strong>Go further:</strong> to let the agent <em>act</em> — autonomously reinvest yield or rebalance to targets — grant it a Scoped session in <a href="/guide/agent/set-tier">H3 · Set the tier</a> and watch it execute in <a href="/guide/agent/autonomous">H4 · Autonomous execution</a>. Prefer your own LLM? Run the same flows over the <a href="/guide/mcp/install">MCP track</a>.</p></blockquote><h2 id="_7-·-verify-on-chain-·-1-min" tabindex="-1">7 · Verify on-chain · ~1 min <a class="header-anchor" href="#_7-·-verify-on-chain-·-1-min" aria-label="Permalink to &quot;7 · Verify on-chain · ~1 min&quot;">​</a></h2><p><a href="/guide/investor/activity">Full task → I12</a></p><ol><li>Open <strong>Activity</strong>.</li><li>Find your <strong>buy</strong> row and click its <strong>Proof</strong> toggle to expand the privacy-proof panel.</li><li>Click <strong>View on Arbiscan</strong> to open the transaction on <a href="https://sepolia.arbiscan.io" target="_blank" rel="noreferrer">sepolia.arbiscan.io</a>. You&#39;ll see the transaction succeeded — and that the <strong>amount is not in cleartext</strong> anywhere in the calldata.</li></ol>',7)),n(i,null,{default:s(()=>[...e[1]||(e[1]=[o(" You signed in with a passkey, funded a wallet, and now hold a ",-1),t("strong",null,"confidential RWA position",-1),o(" — readable by you, opaque to everyone else, and verifiable on a public block explorer. That's MuHaven. ",-1)])]),_:1}),e[6]||(e[6]=a('<h2 id="where-to-next" tabindex="-1">Where to next <a class="header-anchor" href="#where-to-next" aria-label="Permalink to &quot;Where to next&quot;">​</a></h2><ul><li>The full <a href="/guide/investor/sell"><strong>Investor track</strong></a> — sell, claim yield, transfer, withdraw.</li><li>The <a href="/guide/agent/set-tier"><strong>AI agent track</strong></a> — grant autonomy and watch it trade.</li><li>The <a href="/guide/issuer/become-issuer"><strong>Issuer track</strong></a> — issue your own token and distribute yield.</li><li>Stuck? <a href="/guide/troubleshooting"><strong>Troubleshooting &amp; FAQ</strong></a>.</li></ul>',2))])}const _=h(c,[["render",d]]);export{v as __pageData,_ as default};
